import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { useSearchParams } from 'react-router-dom';
import {
  Select,
  SearchTextInput,
  dispatchAppToast,
  LIN_ERP_LIST_FILTER_LAYOUT,
  LinErpListFilterBar,
  LinPageLayout,
  useCatalogTableBusy,
  useErpListSelection,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useStockBalancePermissions } from '../../../hooks/useStockBalancePermissions';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { wmsService } from '../../../services/kho/wmsService';
import type { StockBalanceDto } from '../../../services/kho/models';
import { khoReportPageLabels } from '../../../constants/khoReportPageLabels';
import { formatMoneyVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { LIST_UI_SCHEMA_KIND } from '../../../types/catalogUiSchema';
import { ListUiSchemaEditorModal } from '../../../components/listUiSchema';
import { ReportSchemaListGrid } from '../../../components/list/ReportSchemaListGrid';
import { buildKhoReportListToolbar } from '../../../features/kho/reportListToolbar';
import { withListRowIds } from '../../../utils/listRowIds';
import { StockMaterialLedgerSlideout } from '../../../components/report/StockMaterialLedgerSlideout';
import erp from '../../../styles/erpPage.module.css';

const labels = khoReportPageLabels.tonKho;
const TEST_ID = 'erp-kho-ton-kho';
const PAGE_ID = 'kho-ton-kho';

type StockBalanceRow = StockBalanceDto & { id: string };

const TonKhoPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [searchParams] = useSearchParams();
  useStockBalancePermissions();
  const [warehouseId, setWarehouseId] = useState('');
  const [asOfDate, setAsOfDate] = useState(() => new Date().toISOString().slice(0, 10));
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<StockBalanceDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [showSchemaEditor, setShowSchemaEditor] = useState(false);
  const [ledgerSlideout, setLedgerSlideout] = useState<StockBalanceRow | null>(null);
  const { showTableLoading } = useCatalogTableBusy(loading);

  const { warehouseOptions } = useVoucherInitData('stock-balance-filter');
  const whOpts = [{ value: '', label: labels.warehouseAll }, ...warehouseOptions];

  const gridRows = useMemo(
    () => withListRowIds(items, (r, i) => `${r.materialCode}-${r.warehouseId}-${i}`),
    [items],
  );

  const selection = useErpListSelection({
    rows: gridRows,
    totalCount: gridRows.length,
    page: 1,
    pageSize: Math.max(gridRows.length, 1),
    getRowId: r => r.id,
  });

  useEffect(() => {
    const code = searchParams.get('materialCode')?.trim();
    if (code) {
      setSearchDraft(code);
      setSearch(code);
    }
  }, [searchParams]);

  const handleView = useCallback(() => {
    const nextSearch = searchDraft.trim();
    setSearch(nextSearch);
    setLoading(true);
    wmsService.getStockBalance({
      warehouseId: warehouseId || undefined,
      asOfDate: asOfDate || undefined,
      search: nextSearch || undefined,
    })
      .then(setItems)
      .catch(err => {
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, labels.loadError),
          type: 'error',
        });
      })
      .finally(() => setLoading(false));
  }, [warehouseId, asOfDate, searchDraft, dispatch]);

  const totalAmount = items.reduce((sum, r) => sum + (r.amount ?? 0), 0);
  const hasData = items.length > 0;

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={asOfDate}
        toDate={undefined}
        dateLabel="Đến ngày"
        onDateChange={from => setAsOfDate(from ?? '')}
        onSearch={handleView}
        searchAriaLabel={labels.view}
        loading={showTableLoading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-warehouse`}>
              <Select
                label="Kho"
                value={warehouseId}
                onChange={e => setWarehouseId(e.target.value)}
                options={whOpts}
                fullWidth
                data-testid={`${TEST_ID}-filter-warehouse`}
              />
            </div>
            <div data-testid={`${TEST_ID}-field-search`}>
              <SearchTextInput
                label="Tìm kiếm"
                value={searchDraft}
                onChange={setSearchDraft}
                onSearch={handleView}
                placeholder={labels.searchPlaceholder}
                testId={`${TEST_ID}-search-text`}
              />
            </div>
          </>
        )}
      />
    ),
    [warehouseId, asOfDate, searchDraft, whOpts, handleView, showTableLoading],
  );

  const toolbarProps = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      profile: 'report' as const,
      actions: buildKhoReportListToolbar({
        testIdPrefix: TEST_ID,
        onRefresh: handleView,
        onEditConfig: () => setShowSchemaEditor(true),
        canPrint: hasData,
        onPrint: () => window.print(),
      }),
    }),
    [handleView, hasData],
  );

  const listBody = (
    <ReportSchemaListGrid
      catalogKind={LIST_UI_SCHEMA_KIND.stockBalance}
      testIdPrefix={TEST_ID}
      rows={gridRows}
      showTableLoading={showTableLoading}
      emptyLabel={labels.empty}
      selection={selection}
      onRowDoubleClick={r => setLedgerSlideout(r)}
    />
  );

  return (
    <div
      className={erp.voucherListRoot}
      data-catalog-list-page
      data-report-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="report"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: labels.title,
          titleIconClass: 'fas fa-warehouse',
          pageId: PAGE_ID,
        }}
        toolbarProps={toolbarProps}
        listTitle={labels.listTitle}
        filters={listFilters}
        listLayoutVariant="erp-filter-bar"
        listHeaderClassName={LIN_ERP_LIST_FILTER_LAYOUT.header}
        listFiltersClassName={LIN_ERP_LIST_FILTER_LAYOUT.filtersHost}
        showTableLoading={showTableLoading}
        skeletonRows={8}
        footer={hasData ? (
          <div className={erp.paginationRow} data-testid={`${TEST_ID}-summary`}>
            <span className={erp.totalCount}>
              {labels.summaryItems(items.length, formatMoneyVnd(totalAmount))}
            </span>
          </div>
        ) : undefined}
        modals={(
          <>
            <ListUiSchemaEditorModal
              testIdPrefix={TEST_ID}
              catalogKind={LIST_UI_SCHEMA_KIND.stockBalance}
              isOpen={showSchemaEditor}
              onClose={() => setShowSchemaEditor(false)}
              title="Cấu hình hiển thị danh sách"
              onSaved={handleView}
            />
            <StockMaterialLedgerSlideout
              isOpen={ledgerSlideout != null}
              onClose={() => setLedgerSlideout(null)}
              materialCode={ledgerSlideout?.materialCode ?? ''}
              materialName={ledgerSlideout?.materialName}
              warehouseId={(ledgerSlideout?.warehouseId ?? warehouseId) || undefined}
              asOfDate={asOfDate || undefined}
              testIdPrefix={TEST_ID}
            />
          </>
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default TonKhoPage;
